#!/usr/bin/env node
/**
 * Extracts the canonical n8n payload-size limits from
 * src-tauri/src/commands/design/n8n_limits.rs and emits a TypeScript
 * constant file at src/lib/n8nLimits.generated.ts.
 *
 * Mirrors the existing scripts/generate-command-names.mjs pattern: Rust is
 * the single source of truth, the TS file is auto-generated, and CI verifies
 * the file is up to date so the limits cannot drift.
 *
 * Usage: node scripts/generate-n8n-limits.mjs
 */
import { readFileSync, writeFileSync } from "fs";
import { resolve, dirname } from "path";
import { fileURLToPath } from "url";

const __dirname = dirname(fileURLToPath(import.meta.url));
const ROOT = resolve(__dirname, "..");
const SOURCE = resolve(ROOT, "src-tauri/src/commands/design/n8n_limits.rs");
const OUTPUT = resolve(ROOT, "src/lib/n8nLimits.generated.ts");

const src = readFileSync(SOURCE, "utf-8");

// Match: pub const NAME: usize = N * N * N;  (or any simple integer expr)
// We deliberately accept only `<digits> * <digits> * ...` so the value is
// trivially JS-safe — anything more complex needs a real parser.
function extractConst(name) {
  const re = new RegExp(
    `pub const ${name}\\s*:\\s*usize\\s*=\\s*([\\d_\\s\\*]+);`,
  );
  const match = src.match(re);
  if (!match) {
    console.error(`Could not find pub const ${name} in ${SOURCE}`);
    process.exit(1);
  }
  // Evaluate the simple `n * n * n` expression after stripping underscores.
  const expr = match[1].replace(/_/g, "").trim();
  if (!/^[\d\s\*]+$/.test(expr)) {
    console.error(`Const ${name} has unsupported expression: ${expr}`);
    process.exit(1);
  }
  // Safe arithmetic: only digits, whitespace, and `*`.
  const value = Function(`"use strict"; return (${expr});`)();
  if (!Number.isInteger(value) || value <= 0) {
    console.error(`Const ${name} did not evaluate to a positive integer: ${value}`);
    process.exit(1);
  }
  return { value, expr };
}

const workflow = extractConst("MAX_WORKFLOW_JSON_BYTES");
const transform = extractConst("MAX_TRANSFORM_PAYLOAD_BYTES");

const output = `// AUTO-GENERATED by scripts/generate-n8n-limits.mjs — DO NOT EDIT
// Re-run: node scripts/generate-n8n-limits.mjs
//
// Generated from src-tauri/src/commands/design/n8n_limits.rs.
// Both values must stay in lock-step with the Rust constants; CI fails on drift.

import type { N8nPayloadLimits } from "./bindings/N8nPayloadLimits";

/**
 * Maximum size (bytes) of a single raw workflow JSON accepted by
 * \`create_n8n_session\`. See n8n_limits.rs for the full rationale.
 */
export const MAX_WORKFLOW_JSON_BYTES = ${workflow.expr.replace(/\s+/g, " ")}; // ${workflow.value} bytes

/**
 * Maximum size (bytes) of the combined transform payload (workflow +
 * parser result + adjustment + previous draft) accepted by
 * \`start_n8n_transform_background\`. See n8n_limits.rs for the full rationale.
 */
export const MAX_TRANSFORM_PAYLOAD_BYTES = ${transform.expr.replace(/\s+/g, " ")}; // ${transform.value} bytes

/** Canonical limits as a single struct, matching the Rust ts-rs export. */
export const N8N_PAYLOAD_LIMITS: N8nPayloadLimits = {
  maxWorkflowJsonBytes: MAX_WORKFLOW_JSON_BYTES,
  maxTransformPayloadBytes: MAX_TRANSFORM_PAYLOAD_BYTES,
};
`;

writeFileSync(OUTPUT, output, "utf-8");
console.log(
  `Generated ${OUTPUT} (workflow=${workflow.value}, transform=${transform.value}).`,
);
